#include <bits/stdc++.h>
using namespace std;
int main() {
    int n;
    cin >> n;
    string s;
    cin >> s;
    int m;
    cin >> m;
    string t;
    cin >> t;
    unordered_map<char, int> need;
    for (char c : t) {
        need[c]++;
    }
    int required = need.size();
    int left = 0;
    int min_len = INT_MAX;
    string min_window;
    int formed = 0;
    unordered_map<char, int> window_counts;
    for (int right = 0; right < n; right++) {
        char character = s[right];
        window_counts[character]++;
        if (need.find(character) != need.end() && window_counts[character] == need[character]) {
            formed++;
        }
        while (left <= right && formed == required) {
            character = s[left];
            if (right - left + 1 < min_len) {
                min_len = right - left + 1;
                min_window = s.substr(left, right - left + 1);
            }
            window_counts[character]--;
            if (need.find(character) != need.end() && window_counts[character] < need[character]) {
                formed--;
            }
            left++;
        }
    }
    cout << (min_window.empty() ? "-1" : min_window) << endl;
}
